const input = $input.first().json;
const workflow = input.workflow ?? {};
const execution = input.execution ?? {};
const node = input.node ?? {};
const error = input.error ?? {};
const message = error.message ?? input.message ?? 'Workflow execution failed.';
const knownCodes = [
  'INVALID_INPUT',
  'MISSING_CONTACT_METHOD',
  'MISSING_MESSAGE_CONTENT',
  'UNSUPPORTED_SOURCE',
  'AI_GATEWAY_FAILED',
  'AI_PROVIDER_FAILED',
  'AI_PARSE_FAILED',
  'AI_SCHEMA_VALIDATION_FAILED',
  'CRM_WRITE_FAILED',
  'SLACK_NOTIFY_FAILED',
  'GMAIL_DRAFT_FAILED'
];
const errorText = (error.name ?? '') + ' ' + message;
const error_code = knownCodes.find((code) => errorText.includes(code)) ?? 'UNKNOWN_ERROR';
const workflow_name = workflow.name ?? execution.workflowName ?? 'Unknown Workflow';
const node_name = node.name ?? execution.lastNodeExecuted ?? 'Unknown Node';
const execution_id = execution.id ?? null;
const redacted_input = {
  workflow_name,
  node_name,
  execution_id,
  lead_id: input.lead_id ?? input.lead?.lead_id ?? null,
  source: input.source ?? input.lead?.source ?? null,
  has_error: Boolean(input.error),
  error_name: error.name ?? null
};
const error_log = {
  error_id: 'err_' + Date.now(),
  lead_id: redacted_input.lead_id,
  timestamp: new Date().toISOString(),
  workflow_name,
  node_name,
  error_code,
  error_message: message,
  status: 'FAILED',
  raw_input: redacted_input,
  raw_ai_output: input.raw_ai_output && typeof input.raw_ai_output === 'object' ? {
    lead_type: input.raw_ai_output.lead_type ?? null,
    intent: input.raw_ai_output.intent ?? null,
    priority: input.raw_ai_output.priority ?? null,
    lead_score: input.raw_ai_output.lead_score ?? null,
    crm_fields: input.raw_ai_output.crm_fields ?? null
  } : null
};
const slack_alert = {
  channel: $env.SLACK_CHANNEL_ID || '#sales',
  text: 'LeadOps workflow failed: ' + workflow_name,
  fields: {
    workflow_name,
    node_name,
    error_code,
    error_message: message,
    execution_id
  }
};
return [{ json: { error_log, slack_alert } }];
